			B[3] = ["\u0418\u0433\u0440\u043e\u043a \u0443\u0431\u0438\u043b \u0442\u0435\u0431\u044f \u0438 \u0441\u043a\u0430\u0437\u0430\u043b '\u0441\u0442\u0430\u043d\u044c \u043b\u0443\u0447\u0448\u0435.'", "\u0422\u044b \u0431\u044b\u043b \u0443\u0431\u0438\u0442 \u0438\u0433\u0440\u043e\u043a\u043e\u043c. \u041d\u0435 \u0432\u043e\u043b\u043d\u0443\u0439\u0441\u044f, \u044d\u0442\u043e\u0442 \u0438\u0433\u0440\u043e\u043a \u0442\u043e\u0436\u0435 \u0443\u043c\u0440\u0451\u0442, \u0432 \u043a\u043e\u043d\u0446\u0435 \u043a\u043e\u043d\u0446\u043e\u0432."];
			B[4] = ["\u0412\u044b \u0441\u0442\u043e\u044f\u043b\u0438 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0431\u043b\u0438\u0437\u043a\u043e \u043a \u043e\u0433\u043d\u044e \u0438 \u0441\u0433\u043e\u0440\u0435\u043b\u0438. \u041f\u043b\u043e\u0445\u0430\u044f \u0438\u0434\u0435\u044f.", "\u0422\u044b \u0443\u043c\u0435\u0440 \u043e\u0442 \u043e\u0433\u043d\u044f, \u043e\u043d \u043f\u0440\u0438\u0447\u0438\u043d\u0438\u043b \u0432\u0430\u043c \u0431\u043e\u043b\u044c. \u041d\u0430\u043f\u0438\u0448\u0438\u0442\u0435 \u0438\u0441\u0442\u043e\u0440\u0438\u044e \u043d\u0430\u0441\u0447\u0451\u0442 \u044d\u0442\u043e\u0433\u043e."];
			B[5] = ["\u0412\u0430\u0448\u0435 \u0442\u0435\u043b\u043e \u0441\u0442\u0430\u043d\u0435\u0442 \u0433\u043d\u0435\u0437\u0434\u043e\u043c \u0434\u043b\u044f \u044f\u0438\u0446 \u043f\u0430\u0443\u043a\u0430", "\u041f\u0430\u0443\u043a \u0443\u0431\u0438\u043b \u0432\u0430\u0441. \u041f\u043e \u043a\u0440\u0430\u0439\u043d\u0435\u0439 \u043c\u0435\u0440\u0435 \u044d\u0442\u043e \u0431\u044b\u043b \u043d\u0435 \u043a\u0440\u043e\u043b\u0438\u043a."];
			B[6] = ["\u0412\u043e\u043b\u043a \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0435 \u0431\u0443\u0434\u0435\u0442 \u0433\u043e\u043b\u043e\u0434\u0430\u0442\u044c \u043f\u043e\u0441\u043b\u0435 \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u043d\u0430\u0435\u043b\u0441\u044f \u0432\u0430\u043c\u0438", "\u041e\u043d\u0438 \u043d\u0435 \u0441\u043e\u0431\u0430\u043a\u0438. \u0412\u043e\u043b\u043a\u0438 \u043d\u0435 \u043b\u044e\u0431\u044f\u0442 \u043b\u0430\u0441\u043a\u0430\u0442\u044c\u0441\u044f."];
			B[7] = ["\u041b\u0438\u0441\u0430 \u0431\u044b\u043b\u0430 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0431\u044b\u0441\u0442\u0440\u043e\u0439 \u0434\u043b\u044f \u0432\u0430\u0441", "\u041b\u0438\u0441\u0430 \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0430 \u0442\u0435\u0431\u044f \u0432 \u044f\u0449\u0438\u043a. \u0421 \u043a\u0430\u043a\u0438\u0445 \u043f\u043e\u0440 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0435 \u043e\u0431\u043b\u0430\u0434\u0430\u044e\u0442 \u043c\u0430\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u043c\u0438 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044f\u043c\u0438?"];
			B[8] = ["\u041c\u0435\u0434\u0432\u0435\u0434\u044c \u043f\u0440\u043e\u0441\u0442\u043e \u0445\u043e\u0442\u0435\u043b \u043e\u0431\u043d\u044f\u0442\u044c \u0442\u0435\u0431\u044f.", "\u041c\u0435\u0434\u0432\u0435\u0434\u044c \u0431\u044b\u043b \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0433\u0440\u0443\u0441\u0442\u043d\u044b\u043c. \u041c\u043d\u0435 \u043d\u0435 \u0436\u0430\u043b\u044c."];
			B[9] = ["\u0412\u044b \u0431\u044b\u043b\u0438 \u0441\u043e\u0436\u0436\u0435\u043d\u044b \u0434\u0440\u0430\u043a\u043e\u043d\u043e\u043c. \u0422\u0430\u043a \u0433\u0440\u0443\u0441\u0442\u043d\u043e.", "\u0412\u044b \u0431\u044b\u043b\u0438 \u0441\u043f\u043b\u044e\u0449\u0435\u043d\u044b \u0434\u0440\u0430\u043a\u043e\u043d\u043e\u043c. \u0411\u044b\u0442\u044c \u0440\u0430\u0437\u0434\u0430\u0432\u043b\u0435\u043d\u043d\u044b\u043c - \u044d\u0442\u043e \u0443\u0436\u0430\u0441\u043d\u044b\u0439 \u0441\u043f\u043e\u0441\u043e\u0431 \u0443\u043c\u0435\u0440\u0435\u0442\u044c."];
			B[10] = ["\u0412\u044b \u043f\u0440\u044b\u0433\u043d\u0443\u043b\u0438 \u0432 \u0441\u0442\u0435\u043d\u0443 \u0441 \u0448\u0438\u043f\u0430\u043c\u0438. \u041f\u043b\u043e\u0445\u0430\u044f \u0438\u0434\u0435\u044f...", "\u0412\u044b \u0431\u044b\u043b\u0438 \u0443\u0431\u0438\u0442\u044b \u0441\u0442\u0435\u043d\u043e\u0439 \u0441 \u0448\u0438\u043f\u0430\u043c\u0438. \u0411\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u043b\u044e\u0434\u0435\u0439 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u0440\u0430\u0437\u0443\u043c\u043d\u044b, \u0447\u0442\u043e\u0431\u044b \u043d\u0435 \u043a\u0430\u0441\u0430\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u0440\u044b\u0445 \u0432\u0435\u0449\u0435\u0439."];
			B[11] = ["\u0414\u0430\u0436\u0435 \u043f\u0440\u0438\u0437\u0440\u0430\u043a \u043c\u043e\u0436\u0435\u0442 \u0443\u043c\u0435\u0440\u0435\u0442\u044c.", "\u0412\u044b \u043d\u0435 \u0441\u043c\u043e\u0433\u043b\u0438 \u0432\u043e\u0441\u043a\u0440\u0435\u0441\u043d\u0443\u0442\u044c. \u042d\u0442\u043e \u0438\u0433\u0440\u0430, \u0438 \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u0432\u043e\u0437\u0432\u0440\u0430\u0449\u0430\u0442\u044c\u0441\u044f \u043a \u0436\u0438\u0437\u043d\u0438 \u043f\u043e\u0441\u043b\u0435 \u0441\u043c\u0435\u0440\u0442\u0438, \u0442\u0430\u043a \u0447\u0442\u043e..."];
			B[12] = ["\u0411\u0430\u043a\u0442\u0435\u0440\u0438\u044f \u0438\u0437 \u0432\u0430\u0448\u0435\u0439 \u0441\u044b\u0440\u043e\u0439 \u043f\u0438\u0449\u0438 \u0443\u0431\u0438\u043b\u0430 \u0432\u0430\u0441. \u042d\u0442\u0430 \u0438\u0433\u0440\u0430 \u0431\u0435\u0437\u0443\u0441\u043b\u043e\u0432\u043d\u043e \u0441\u043b\u043e\u0436\u043d\u0430.", "\u0412\u044b \u0443\u0431\u0438\u043b\u0438 \u0441\u044b\u0440\u0443\u044e \u043f\u0438\u0449\u0443. \u041e\u043d\u0430 \u0442\u043e\u0436\u0435 \u0442\u0435\u0431\u044f \u0443\u0431\u0438\u043b\u0430."];
			B[13] = ["\u0412\u044b \u0443\u043c\u0435\u0440\u043b\u0438 \u043e\u0442 \u0436\u0430\u0436\u0434\u044b. \u041b\u0443\u0447\u0448\u0435 \u043f\u0438\u0442\u044c \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u043c\u043e\u0447\u0443."];
			B[14] = ["\u0417\u043d\u0430\u0435\u0448\u044c \u043b\u0438 \u0442\u044b, \u0447\u0442\u043e \u0443 \u0433\u043e\u043b\u043e\u0434\u0430\u044e\u0449\u0438\u0445 \u0440\u043e\u0442 \u0432\u0441\u0435\u0433\u0434\u0430 \u043f\u043e\u0434 \u0432\u043e\u0434\u043e\u0439, \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u0438 \u043f\u043b\u0430\u0432\u0430\u044e\u0442? \u0422\u0435\u043f\u0435\u0440\u044c \u0442\u044b \u0437\u043d\u0430\u0435\u0448\u044c."];
			B[15] = ["\u041d\u0435 \u0432\u043e\u043b\u043d\u0443\u0439\u0441\u044f, \u043f\u0438\u0440\u0430\u043d\u044c\u044f \u0441\u043e\u0447\u043b\u0430 \u0442\u0435\u0431\u044f \u0432\u043a\u0443\u0441\u043d\u044b\u043c.", "\u0412\u0435\u0441\u0435\u043b\u044b\u0439 \u0444\u0430\u043a\u0442: \u041f\u0438\u0440\u0430\u043d\u044c\u0438 \u0435\u0434\u044f\u0442 \u043b\u044e\u0434\u0435\u0439. \u0412 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0442\u0435\u0431\u044f."];
			B[16] = ["LapaMauve \u043d\u0435 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043b, \u0447\u0442\u043e \u0442\u044b \u0443\u0431\u044c\u0451\u0448\u044c \u043a\u0440\u0430\u043a\u0435\u043d\u0430", "\u041a\u0440\u0430\u043a! \u041a\u0440\u0430\u043a\u0435\u043d \u0441\u043b\u043e\u043c\u0430\u043b \u0442\u0432\u043e\u0439 \u0447\u0435\u0440\u0435\u043f."];
			B[17] = ["\u0422\u0432\u043e\u044f \u043a\u043e\u0436\u0430 \u0440\u0430\u0437\u0432\u0430\u043b\u0438\u0432\u0430\u0435\u0442\u0441\u044f, \u0441\u043e\u043b\u043d\u0446\u0435 \u0443\u0431\u0438\u043b\u043e \u0442\u0435\u0431\u044f"];
			B[18] = ["\u0427\u0435\u0441\u043d\u043e\u043a, \u0445\u0440\u0430\u043d\u044f\u0449\u0438\u0439\u0441\u044f \u0432 \u0442\u0432\u043e\u0438\u0445 \u043a\u0430\u0440\u043c\u0430\u043d\u0430\u0445 \u0441\u0432\u0430\u0440\u0438\u043b \u0442\u0432\u043e\u0439 \u043c\u043e\u0437\u0433."];
			B[19] = ["\u041d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0441\u0442\u043e\u044f\u0442\u044c \u0440\u044f\u0434\u043e\u043c \u0441 \u0447\u0435\u0441\u043d\u043e\u0447\u043d\u044b\u043c \u0437\u0443\u0431\u043a\u043e\u043c, \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u0432\u0430\u043c\u043f\u0438\u0440."];
